const hound = Hound.create({
  db: redis,
  ctx: { db: myDatabase, config: appConfig },
  concurrency: 25,
  auth: Deno.env.get('HOUND_TOKEN'),
  importMeta: import.meta,
  jobDirs: ['./jobs'],
  processor: { pollIntervalMs: 500 },
});

const hound = Hound.create({
  db: redis,
  processor: {
    retry: {
      retryDelayMs: 2_000,
      retryBackoff: 'exponential',
    },
  },
});

const hound = Hound.create({
  db: redis,
  processor: {
    dlq: {
      streamKey: 'hound:dlq',
    },
  },
});
